const r=n=>{const t=Number(n);return Number.isFinite(t)?t:0},i=(n,t=1)=>{const e=r(n),u=10**t;return Math.round(e*u)/u},l=n=>{const t=r(n),e=i(t,1);return Number.isInteger(e)?`${Math.round(e)} kcal`:`${e} kcal`},m=(n,t)=>{const e=r(n),u=r(t);if(!e||!u)return 0;const o=e/100;return i(u/(o*o))},f=(n,t,e,u)=>{const o=r(n),s=r(t),c=r(e),a=r(u);if(!s||!c||!a)return 0;const g=o===1?5:o===2?-161:-78;return Math.round(10*a+6.25*c-5*s+g)},h=n=>{const t=r(n);return t?t<18.5?"偏瘦":t<24?"正常":t<28?"偏高":"超重":"待完善"};export{f as a,m as c,l as f,h as g,i as r,r as t};
